{
  "lessons": [
    {
      "description": "Conjugate regular -AR verbs like hablar, trabajar, and caminar across all persons. Build the full paradigm: hablo, hablas, habla, hablamos, hablan.",
      "kind": "grammar",
      "title": "-AR Verb Conjugation"
    },
    {
      "description": "Conjugate regular -ER verbs like comer, beber, and correr across all persons. Build the full paradigm: como, comes, come, comemos, comen.",
      "kind": "grammar",
      "title": "-ER Verb Conjugation"
    },
    {
      "description": "Conjugate regular -IR verbs like vivir, escribir, and abrir across all persons. Build the full paradigm: vivo, vives, vive, vivimos, viven.",
      "kind": "grammar",
      "title": "-IR Verb Conjugation"
    },
    {
      "description": "Use ser to express permanent identity, origin, and characteristics. Recognize all present-tense forms: soy, eres, es, somos, son.",
      "kind": "grammar",
      "title": "Ser in the Present Tense"
    },
    {
      "description": "Use estar to express location, states, and temporary conditions. Recognize all present-tense forms: estoy, estás, está, estamos, están.",
      "kind": "grammar",
      "title": "Estar in the Present Tense"
    },
    {
      "description": "Choose between ser and estar in context. Compare permanent traits versus temporary states, and practice both verbs side by side.",
      "kind": "grammar",
      "title": "Ser vs. Estar"
    },
    {
      "description": "Conjugate tener in the present tense and use it to express possession and necessity. Recognize the irregular yo form tengo and the full paradigm: tengo, tienes, tiene, tenemos, tienen.",
      "kind": "grammar",
      "title": "Tener in the Present Tense"
    },
    {
      "description": "Conjugate ir in the present tense and use it to talk about destinations with a. Recognize all forms: voy, vas, va, vamos, van.",
      "kind": "grammar",
      "title": "Ir in the Present Tense"
    },
    {
      "description": "Recognize and use common everyday action verbs: hablar, comer, vivir, trabajar, estudiar, caminar, beber, escribir, leer, and escuchar.",
      "kind": "vocabulary",
      "title": "Everyday Action Verbs"
    },
    {
      "description": "Express daily routines using present-tense verbs: waking up, eating, going to work or school, and sleeping. Connect verbs to real daily sequences.",
      "kind": "vocabulary",
      "title": "Daily Routine Expressions"
    },
    {
      "description": "Use subject pronouns yo, tú, él, ella, usted, nosotros, ellos, ellas, and ustedes correctly with present-tense verbs. Understand when to include or drop them in Latin American Spanish.",
      "kind": "grammar",
      "title": "Subject Pronouns and Verb Agreement"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Reconheça e use cumprimentos comuns como hello, hi, good morning, good afternoon e good evening em diferentes situações do dia a dia.",
      "kind": "vocabulary",
      "title": "Cumprimentos do Dia a Dia"
    },
    {
      "description": "Use expressões de despedida como goodbye, bye, see you later, good night e take care para encerrar conversas de forma natural.",
      "kind": "vocabulary",
      "title": "Despedidas Comuns"
    },
    {
      "description": "Apresente-se usando expressões como my name is, I'm e I'm from para dizer seu nome e origem.",
      "kind": "vocabulary",
      "title": "Apresentações Pessoais"
    },
    {
      "description": "Faça e responda perguntas básicas como What's your name?, Where are you from? e How are you? em contextos de apresentação.",
      "kind": "vocabulary",
      "title": "Perguntas de Apresentação"
    },
    {
      "description": "Use expressões de cortesia como please, thank you, you're welcome, excuse me e I'm sorry em interações cotidianas.",
      "kind": "vocabulary",
      "title": "Expressões de Cortesia"
    },
    {
      "description": "Compare o uso de I'm e my name is para se apresentar, e entenda como formar frases simples com o verbo to be no presente (I am, you are, he/she is).",
      "kind": "grammar",
      "title": "Verbo To Be nas Apresentações"
    },
    {
      "description": "Distinga o uso de formal e informal em saudações e apresentações, como hi vs. hello e how are you vs. how do you do, escolhendo a forma adequada ao contexto.",
      "kind": "grammar",
      "title": "Registro Formal e Informal"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Reconheça e escreva as cinco vogais do hiragana: あ、い、う、え、お. Estas são a base de todo o sistema hiragana.",
      "kind": "alphabet",
      "title": "Vogais: あいうえお"
    },
    {
      "description": "Reconheça e escreva os sons da linha K: か、き、く、け、こ. Associe cada símbolo ao seu som correspondente.",
      "kind": "alphabet",
      "title": "Linha K: かきくけこ"
    },
    {
      "description": "Reconheça e escreva os sons da linha S: さ、し、す、せ、そ. Atenção especial ao som irregular de し (shi).",
      "kind": "alphabet",
      "title": "Linha S: さしすせそ"
    },
    {
      "description": "Reconheça e escreva os sons da linha T: た、ち、つ、て、と. Atenção aos sons irregulares de ち (chi) e つ (tsu).",
      "kind": "alphabet",
      "title": "Linha T: たちつてと"
    },
    {
      "description": "Reconheça e escreva os sons da linha N: な、に、ぬ、ね、の. Associe cada símbolo ao seu som correspondente.",
      "kind": "alphabet",
      "title": "Linha N: なにぬねの"
    },
    {
      "description": "Reconheça e escreva os sons da linha H: は、ひ、ふ、へ、ほ. Atenção ao som especial de ふ (fu).",
      "kind": "alphabet",
      "title": "Linha H: はひふへほ"
    },
    {
      "description": "Reconheça e escreva os sons da linha M: ま、み、む、め、も. Associe cada símbolo ao seu som correspondente.",
      "kind": "alphabet",
      "title": "Linha M: まみむめも"
    },
    {
      "description": "Reconheça e escreva os sons da linha Y: や、ゆ、よ. Esta linha tem apenas três símbolos que representam sons semivocálicos.",
      "kind": "alphabet",
      "title": "Linha Y: やゆよ"
    },
    {
      "description": "Reconheça e escreva os sons da linha R: ら、り、る、れ、ろ. O som de R em japonês é diferente do R português.",
      "kind": "alphabet",
      "title": "Linha R: らりるれろ"
    },
    {
      "description": "Reconheça e escreva わ、を e o símbolo ん. Entenda que を é usado quase exclusivamente como partícula e ん é uma consoante silábica.",
      "kind": "alphabet",
      "title": "わ、を e ん"
    },
    {
      "description": "Reconheça e use o dakuten (゛) para transformar sons surdos em sonoros: が行、ざ行、だ行、ば行. Compare cada par de símbolos com e sem dakuten.",
      "kind": "alphabet",
      "title": "Dakuten: が・ざ・だ・ば行"
    },
    {
      "description": "Reconheça e use o handakuten (゜) para formar os sons da linha P: ぱ、ぴ、ぷ、ぺ、ぽ. Compare ぱ行 com は行 e ば行.",
      "kind": "alphabet",
      "title": "Handakuten: ぱぴぷぺぽ"
    },
    {
      "description": "Reconheça e leia as combinações yōon formadas com い-sons + や、ゆ、よ pequenos: きゃ、しゃ、ちゃ、にゃ、ひゃ、みゃ、りゃ e suas variações. Entenda como dois caracteres formam um único som.",
      "kind": "alphabet",
      "title": "Combinações Yōon: きゃ・しゃ・ちゃ e variações"
    },
    {
      "description": "Reconheça e leia as combinações yōon com dakuten e handakuten: ぎゃ、じゃ、びゃ、ぴゃ e variações. Compare com as formas sem dakuten/handakuten.",
      "kind": "alphabet",
      "title": "Yōon com Dakuten e Handakuten"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Recognize and pronounce the ten basic Korean vowels: ㅏ, ㅑ, ㅓ, ㅕ, ㅗ, ㅛ, ㅜ, ㅠ, ㅡ, and ㅣ. Distinguish the sounds and shapes of vertical versus horizontal vowel strokes.",
      "kind": "alphabet",
      "title": "Basic Vowels"
    },
    {
      "description": "Recognize and pronounce the nine basic Korean consonants: ㄱ, ㄴ, ㄷ, ㄹ, ㅁ, ㅂ, ㅅ, ㅇ, and ㅈ. Match each consonant shape to its sound in the initial position.",
      "kind": "alphabet",
      "title": "Basic Consonants"
    },
    {
      "description": "Recognize and pronounce the five tense consonants ㄲ, ㄸ, ㅃ, ㅆ, ㅉ and the four aspirated consonants ㅋ, ㅌ, ㅍ, ㅊ. Contrast their sounds with their plain counterparts.",
      "kind": "alphabet",
      "title": "Tense and Aspirated Consonants"
    },
    {
      "description": "Read and write simple syllable blocks that combine one initial consonant and one vowel (CV shape), such as 가, 나, 도, and 무. Understand how consonants and vowels are positioned within a block depending on vowel orientation.",
      "kind": "alphabet",
      "title": "CV Syllable Blocks"
    },
    {
      "description": "Read and write syllable blocks that include a final consonant (받침), such as 강, 밥, and 닭. Recognize how the third position is occupied and how the block shape adjusts.",
      "kind": "alphabet",
      "title": "Final Consonant Position (받침)"
    },
    {
      "description": "Distinguish visually similar consonant pairs like ㄱ/ㅋ, ㄷ/ㅌ, ㅂ/ㅍ, and ㅅ/ㅆ inside full syllable blocks. Choose the correct letter when shapes look nearly identical.",
      "kind": "alphabet",
      "title": "Similar Consonant Shapes"
    },
    {
      "description": "Distinguish visually similar vowel pairs like ㅏ/ㅓ, ㅗ/ㅜ, and ㅡ/ㅣ inside syllable blocks. Read minimal pairs such as 가/거 and 고/구 to sharpen vowel recognition.",
      "kind": "alphabet",
      "title": "Similar Vowel Shapes"
    },
    {
      "description": "Read whole syllable blocks aloud at normal speed by applying consonant and vowel knowledge together. Practice common two- and three-syllable words like 한국, 사람, and 이름.",
      "kind": "alphabet",
      "title": "Reading Syllable Blocks"
    },
    {
      "description": "Use essential beginner words—numbers 1–10, colors, and basic nouns like 책, 물, and 문—spelled in Hangul. Connect Hangul reading to real vocabulary from the start.",
      "kind": "vocabulary",
      "title": "Core Beginner Words in Hangul"
    },
    {
      "description": "Understand how Korean syllables fit the patterns CV, V, CVC, and VC. Recognize why every syllable block must contain at least one vowel and how the silent placeholder ㅇ works in the initial position.",
      "kind": "grammar",
      "title": "Syllable Block Structure Rules"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Usa 'would + infinitivo' para hablar de situaciones hipotéticas o imaginarias en el presente y futuro, como 'I would travel' o 'She would help'.",
      "kind": "grammar",
      "title": "Would + infinitivo"
    },
    {
      "description": "Forma oraciones condicionales hipotéticas completas con 'If + pasado simple, would + infinitivo', como 'If I had more time, I would exercise every day'.",
      "kind": "grammar",
      "title": "Segunda condicional: estructura base"
    },
    {
      "description": "Distingue cuándo usar 'could' y 'might' en lugar de 'would' en la cláusula principal, como 'If it rained, we could stay inside' o 'If she called, I might answer'.",
      "kind": "grammar",
      "title": "Could y might en la condicional hipotética"
    },
    {
      "description": "Compara 'were' y 'was' en la cláusula con 'if' para situaciones hipotéticas, incluyendo la forma formal 'If I were you...' y su uso en el habla cotidiana.",
      "kind": "grammar",
      "title": "Were vs. was en condicionales hipotéticas"
    },
    {
      "description": "Reconoce y forma preguntas y negaciones dentro de la segunda condicional, como 'Would you move if you could?' o 'I wouldn't go if I were tired'.",
      "kind": "grammar",
      "title": "Preguntas y negaciones en la segunda condicional"
    },
    {
      "description": "Palabras y expresiones clave para hablar de situaciones hipotéticas: 'imagine', 'suppose', 'what if', 'in that case', 'otherwise', 'then'.",
      "kind": "vocabulary",
      "title": "Expresiones para plantear hipótesis"
    },
    {
      "description": "Vocabulario frecuente en oraciones condicionales hipotéticas sobre decisiones de vida: trabajo, dinero, viajes, relaciones y salud, como 'quit my job', 'win the lottery', 'move abroad'.",
      "kind": "vocabulary",
      "title": "Situaciones hipotéticas comunes"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Use vocabulário para descrever aparência física e estado visual de pessoas e coisas, como expressões para 'parece cansado', 'parece novo', 'parece delicioso', entre outras.",
      "kind": "vocabulary",
      "title": "Aparência e Estado Visual"
    },
    {
      "description": "Reconheça e use 〜そうだ para expressar que algo parece de determinada forma com base na observação direta. Pratique a conjugação com adjetivos-い, adjetivos-な e verbos.",
      "kind": "grammar",
      "title": "〜そうだ de Aparência (Observação Direta)"
    },
    {
      "description": "Reconheça e use 〜そうだ para transmitir informações ouvidas de terceiros, diferenciando essa função da forma de aparência. Compare as duas formas com exemplos contrastivos.",
      "kind": "grammar",
      "title": "〜そうだ de Boato (Informação Ouvida)"
    },
    {
      "description": "Use 〜らしい para expressar suposições baseadas em evidências indiretas ou no que é típico de algo. Compare com 〜そうだ e identifique contextos onde 〜らしい é mais natural.",
      "kind": "grammar",
      "title": "〜らしい: Evidência Indireta e Tipicidade"
    },
    {
      "description": "Use 〜みたい para expressar suposições com base em aparência ou semelhança, em registro informal. Compare com 〜らしい e 〜そうだ para perceber diferenças de nuance e uso.",
      "kind": "grammar",
      "title": "〜みたい: Comparação e Suposição Informal"
    },
    {
      "description": "Distinga quando usar 〜そうだ, 〜らしい e 〜みたい em situações reais. Compare o grau de formalidade, a fonte de evidência e a nuance de cada estrutura.",
      "kind": "grammar",
      "title": "Diferenças de Registro e Nuance entre 〜そうだ, 〜らしい e 〜みたい"
    },
    {
      "description": "Pratique expressões conversacionais comuns usadas para fazer suposições e comentar sobre aparências no dia a dia, como frases para concordar com uma suposição ou expressar dúvida.",
      "kind": "vocabulary",
      "title": "Expressões de Suposição no Cotidiano"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Distinguish pairs like 'maison' vs. 'foyer', 'erreur' vs. 'faute', and 'chance' vs. 'hasard' by the emotional weight and implication each word carries.",
      "kind": "vocabulary",
      "title": "Connotation in Near-Synonym Pairs"
    },
    {
      "description": "Compare formal, neutral, and familiar synonyms such as 'visage / figure / tronche', 'fatigué / crevé / épuisé', and 'parler / causer / jaser' to feel the social stakes of each choice.",
      "kind": "vocabulary",
      "title": "Register Levels Across Synonyms"
    },
    {
      "description": "Choose correctly between verbs with overlapping meanings: 'regarder' vs. 'observer' vs. 'fixer', 'entendre' vs. 'écouter', and 'savoir' vs. 'connaître'.",
      "kind": "vocabulary",
      "title": "Perception & Knowledge Verbs"
    },
    {
      "description": "Recognize when 'peur', 'crainte', 'effroi', and 'terreur' each fit, and do the same for 'colère', 'irritation', 'rage', and 'courroux', matching intensity and tone to context.",
      "kind": "vocabulary",
      "title": "Emotion Words by Intensity & Tone"
    },
    {
      "description": "Distinguish 'obtenir', 'acquérir', 'gagner', 'remporter', and 'décrocher' by the kind of effort, luck, or formality implied in each acquisition.",
      "kind": "vocabulary",
      "title": "Synonyms for Getting & Achieving"
    },
    {
      "description": "Navigate the subtle differences between 'beau', 'joli', 'magnifique', 'ravissant', and 'superbe', and between 'petit', 'minuscule', 'modeste', and 'exigu', matching adjective to noun and context.",
      "kind": "vocabulary",
      "title": "Descriptive Adjectives & Their Nuance"
    },
    {
      "description": "Contrast 'mais', 'cependant', 'pourtant', 'néanmoins', and 'toutefois' as concession and contrast markers, understanding which register and clause structure each prefers.",
      "kind": "grammar",
      "title": "Concession & Contrast Connectors"
    },
    {
      "description": "Compare 'donc', 'ainsi', 'par conséquent', 'du coup', and 'c'est pourquoi' to understand which signal logical consequence and which are too casual or too formal for a given context.",
      "kind": "grammar",
      "title": "Consequence & Conclusion Connectors"
    },
    {
      "description": "Understand how the same adjective shifts meaning when placed before versus after a noun: 'un grand homme' vs. 'un homme grand', 'un certain charme' vs. 'un charme certain'.",
      "kind": "grammar",
      "title": "Adjective Position & Meaning Shift"
    },
    {
      "description": "Recognize how negation variants—'ne…pas', 'ne…point', 'ne…guère', 'ne…nullement'—differ in formality, emphasis, and the degree of negation they express.",
      "kind": "grammar",
      "title": "Negation Variants & Their Register"
    },
    {
      "description": "Compare 'sembler', 'paraître', 'avoir l'air', and 'donner l'impression de' for how each frames appearance versus reality and fits into different registers.",
      "kind": "vocabulary",
      "title": "Verbs of Appearance & Impression"
    },
    {
      "description": "Explore how word choice in a single sentence shifts its implied attitude: irony markers, understatement with 'pas mal', and litotes like 'ce n'est pas sans intérêt'.",
      "kind": "grammar",
      "title": "Litotes, Understatement & Irony Signals"
    }
  ]
}
